import{_ as a,o as r,c as l,ai as o}from"./chunks/framework.CsYGeNYI.js";const g=JSON.parse('{"title":"Telegram 允许列表加固","description":"","frontmatter":{"read_when":["查看历史 Telegram 允许列表更改"],"summary":"Telegram 允许列表加固：前缀 + 空白规范化","title":"Telegram 允许列表加固","x-i18n":{"generated_at":"2026-02-03T07:47:16Z","model":"claude-opus-4-5","provider":"pi","source_hash":"a2eca5fcc85376948cfe1b6044f1a8bc69c7f0eb94d1ceafedc1e507ba544162","source_path":"experiments/plans/group-policy-hardening.md","workflow":15}},"headers":[],"relativePath":"zh-CN/experiments/plans/group-policy-hardening.md","filePath":"zh-CN/experiments/plans/group-policy-hardening.md","lastUpdated":1771906665000}'),d={name:"zh-CN/experiments/plans/group-policy-hardening.md"};function t(c,e,n,i,s,h){return r(),l("div",null,[...e[0]||(e[0]=[o('<h1 id="telegram-允许列表加固" tabindex="-1"><a class="header-anchor" href="#telegram-允许列表加固">#</a> Telegram 允许列表加固</h1><p><strong>日期</strong>：2026-01-05<br><strong>状态</strong>：已完成<br><strong>PR</strong>：#216</p><h2 id="摘要" tabindex="-1"><a class="header-anchor" href="#摘要">#</a> 摘要</h2><p>Telegram 允许列表现在不区分大小写地接受 <code>telegram:</code> 和 <code>tg:</code> 前缀，并容忍意外的空白。这使入站允许列表检查与出站发送规范化保持一致。</p><h2 id="更改内容" tabindex="-1"><a class="header-anchor" href="#更改内容">#</a> 更改内容</h2><ul><li>前缀 <code>telegram:</code> 和 <code>tg:</code> 被同等对待（不区分大小写）。</li><li>允许列表条目会被修剪；空条目会被忽略。</li></ul><h2 id="示例" tabindex="-1"><a class="header-anchor" href="#示例">#</a> 示例</h2><p>以下所有形式都被接受为同一 ID：</p><ul><li><code>telegram:123456</code></li><li><code>TG:123456</code></li><li><code>tg:123456</code></li></ul><h2 id="为什么重要" tabindex="-1"><a class="header-anchor" href="#为什么重要">#</a> 为什么重要</h2><p>从日志或聊天 ID 复制/粘贴通常会包含前缀和空白。规范化可避免在决定是否在私信或群组中响应时出现误判。</p><h2 id="相关文档" tabindex="-1"><a class="header-anchor" href="#相关文档">#</a> 相关文档</h2><ul><li><a href="/docs/channels/groups">群聊</a></li><li><a href="/docs/channels/telegram">Telegram 提供商</a></li></ul>',13)])])}const m=a(d,[["render",t]]);export{g as __pageData,m as default}